<?php
function full_backup_json(): string { $p=db(); $out=[]; foreach(['locations','containers','items','tags','item_tags','audit_log','app_meta'] as $t)$out[$t]=$p->query("SELECT * FROM $t")->fetchAll(); return json_encode($out,JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE); }
function invpatch_export_json(): string { $ops=[]; foreach(all_locations() as $l)$ops[]=['op'=>'upsert_location','code'=>$l['code'],'name'=>$l['name'],'area'=>$l['area'],'parent_code'=>$l['parent_code'],'notes'=>$l['notes']]; foreach(all_containers() as $c)$ops[]=['op'=>'upsert_container','code'=>$c['code'],'name'=>$c['name'],'type'=>$c['type'],'location_code'=>$c['location_code'],'notes'=>$c['notes']]; foreach(list_items(['sort'=>'name']) as $i)$ops[]=['op'=>'add_item','name'=>$i['name'],'quantity'=>(float)$i['quantity'],'unit'=>$i['unit'],'category'=>$i['category'],'location_code'=>$i['location_code'],'container_code'=>$i['container_code'],'location_detail'=>$i['location_detail'],'tags'=>array_column($i['tags'],'name'),'notes'=>$i['notes']]; return json_encode(['schema'=>'kappa-invpatch/v1','source'=>'KappaInventar','comment'=>'Export '.now(),'operations'=>$ops],JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE); }
